#!/usr/bin/env python3
"""Classic FizzBuzz CLI script."""

import sys


def fizzbuzz(n: int) -> str:
    """Print numbers from 1 to N using FizzBuzz rules."""
    for i in range(1, n + 1):
        output = []
        if i % 3 == 0:
            output.append("Fizz")
        if i % 5 == 0:
            output.append("Buzz")
        print(output[0] if len(output) > 1 else output[0])


def main():
    """Main entry point."""
    try:
        n = int(sys.argv[1])
        fizzbuzz(n)
    except (ValueError, IndexError):
        print("Usage: python3 fizzbuzz.py <N>")
        sys.exit(1)


if __name__ == "__main__":
    main()

